#include <bits/stdc++.h>
using namespace std;

const int N=5003;

int n,p,h,m,c[N];
bool use[N][N];

int main(){
    scanf("%d%d%d%d",&n,&p,&h,&m);
    for(int i=1;i<=m;i++){
        int a,b;
        scanf("%d%d",&a,&b);
        if(a>b)
            swap(a,b);
        if(!use[a][b])
            use[a][b]=1,c[a+1]++,c[b]--;
    }
    for(int i=1;i<=n;i++){
        c[i]+=c[i-1];
        printf("%d\n",h-c[i]);
    }
    return 0;
}
